import React from 'react';
import { Upload } from 'lucide-react';

const UploadPage = () => {
    return (
        <div className="flex flex-col items-center justify-center min-h-[60vh] text-center px-4">
            <div className="bg-orange-50 p-6 rounded-full text-orange-600 mb-6">
                <Upload size={48} />
            </div>
            <h1 className="text-3xl font-bold text-gray-900 mb-2">Upload Analysis</h1>
            <p className="text-gray-600 max-w-md">
                Upload your medical reports (PDF or Image) for AI-powered analysis.
                <br />
                <span className="text-sm font-semibold text-orange-600 mt-2 block">Coming Soon</span>
            </p>
        </div>
    );
};

export default UploadPage;
